import{_ as a,o as s,c as i,a2 as t}from"./chunks/framework.BKG_UbFK.js";const h=JSON.parse('{"title":"Installation","description":"","frontmatter":{},"headers":[],"relativePath":"fr/guide/installation.md","filePath":"fr/guide/installation.md"}'),l={name:"fr/guide/installation.md"};function n(r,e,o,c,d,p){return s(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h1><h2 id="prerequis" tabindex="-1">Prérequis <a class="header-anchor" href="#prerequis" aria-label="Permalink to &quot;Prérequis&quot;">​</a></h2><p>Consultez le <a href="/clearance-docs/fr/guide/introduction.html#requirements">tableau des prérequis</a> complet sur la page Introduction - PHP ^8.3, Laravel ^11.0|^12.0|^13.0, spatie/laravel-permission ^6.0, livewire/livewire ^3.0|^4.0, livewire/flux ^2.14.</p><h2 id="installer-le-package" tabindex="-1">Installer le package <a class="header-anchor" href="#installer-le-package" aria-label="Permalink to &quot;Installer le package&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">composer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> require</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rivalex/clearance</span></span></code></pre></div><h2 id="lancer-l-installateur" tabindex="-1">Lancer l&#39;installateur <a class="header-anchor" href="#lancer-l-installateur" aria-label="Permalink to &quot;Lancer l&#39;installateur&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:install</span></span></code></pre></div><div class="danger custom-block"><p class="custom-block-title">Exécutez toujours clearance:install, jamais un simple migrate</p><p>Les migrations propres à Clearance dépendent de l&#39;existence préalable des tables <code>roles</code>/<code>permissions</code> de Spatie ; l&#39;installateur publie et exécute les migrations de Spatie avant les siennes. Si vous exécutez directement <code>php artisan migrate</code> sur une installation neuve alors que Spatie n&#39;est pas encore configuré, vous obtiendrez un message d&#39;erreur explicite vous indiquant d&#39;exécuter l&#39;installateur à la place.</p></div><h3 id="options-facultatives" tabindex="-1">Options facultatives <a class="header-anchor" href="#options-facultatives" aria-label="Permalink to &quot;Options facultatives&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td><code>--user=ID</code></td><td>Assigne le rôle <code>super_admin</code> à un utilisateur après l&#39;installation</td></tr><tr><td><code>--role=NAME</code></td><td>Assigne <code>clearance-access</code> à un rôle (créé s&#39;il est absent)</td></tr><tr><td><code>--super-admin-role=NAME</code></td><td>Promeut un rôle existant en <code>super_admin</code> (évite l&#39;invite interactive)</td></tr><tr><td><code>--force</code></td><td>Relance même si déjà installé</td></tr></tbody></table><h3 id="ce-que-fait-l-installateur" tabindex="-1">Ce que fait l&#39;installateur <a class="header-anchor" href="#ce-que-fait-l-installateur" aria-label="Permalink to &quot;Ce que fait l&#39;installateur&quot;">​</a></h3><ol><li>Publie <code>config/clearance.php</code>.</li><li>Publie les migrations de Clearance.</li><li>Détecte les tables Spatie Permission - si la table <code>roles</code> est absente, publie et exécute d&#39;abord automatiquement les migrations de Spatie.</li><li>Exécute toutes les migrations en attente.</li><li>Crée <code>clearance-access</code> ainsi que les 5 permissions de capacité fines : <code>clearance-permissions-write</code>, <code>clearance-roles-write</code>, <code>clearance-guards-write</code>, <code>clearance-settings-write</code>, <code>clearance-users-write</code>.</li><li>Crée le rôle <code>super_admin</code> avec toutes les permissions <code>clearance-*</code> assignées (additif - ne retire jamais de permissions existantes lors d&#39;une relance).</li><li>Écrit <code>storage/.clearance-installed</code> comme marqueur d&#39;idempotence.</li></ol><div class="tip custom-block"><p class="custom-block-title">Migration depuis une installation Spatie existante ?</p><p>Utilisez <code>php artisan clearance:backfill</code> plutôt que de repartir de zéro, et lisez d&#39;abord le <a href="/clearance-docs/fr/guide/migration.html">guide de migration</a> - il couvre la collision avec <code>super_admin</code>, les sous-classes de modèle personnalisées, et l&#39;import des gardes.</p></div><h2 id="ajouter-hasclearance-a-votre-modele-user" tabindex="-1">Ajouter HasClearance à votre modèle User <a class="header-anchor" href="#ajouter-hasclearance-a-votre-modele-user" aria-label="Permalink to &quot;Ajouter HasClearance à votre modèle User&quot;">​</a></h2><p>Pour utiliser les méthodes d&#39;autorisation contextuelle (<code>$user-&gt;canIn()</code>, <code>$user-&gt;hasRoleIn()</code>), ajoutez le trait <code>HasClearance</code> à <code>App\\Models\\User</code>. Il inclut déjà <code>HasRoles</code> de Spatie - une seule ligne remplace les deux :</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">use</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Rivalex\\Clearance\\Traits\\HasClearance</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> User</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> extends</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Authenticatable</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    use</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> HasClearance</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// includes HasRoles + all contextual authorization methods</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Vous utilisez déjà <code>use HasRoles</code> ?</p><p>Remplacez-le par <code>use HasClearance</code>, ou gardez les deux - PHP dédoublonne automatiquement la composition de traits, sans conflit.</p></div><p>Sans ce trait, <code>$user-&gt;canIn()</code> et les méthodes associées ne sont pas disponibles, mais les directives Blade (<code>@canin</code>, <code>@hasrolein</code>) et <code>ContextService</code> continuent de fonctionner dans tous les cas - elles ne dépendent pas du trait. Voir <a href="/clearance-docs/fr/features/contextual-authorization.html">Autorisation contextuelle</a> pour plus de détails.</p><h2 id="prochaines-etapes" tabindex="-1">Prochaines étapes <a class="header-anchor" href="#prochaines-etapes" aria-label="Permalink to &quot;Prochaines étapes&quot;">​</a></h2><p>Continuez avec le <a href="/clearance-docs/fr/guide/quick-start.html">Démarrage rapide</a> pour monter le panneau et commencer à gérer les permissions.</p>`,20)])])}const m=a(l,[["render",n]]);export{h as __pageData,m as default};
